import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-cv-builder',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './cv-builder.component.html',
  styleUrls: ['./cv-builder.component.css']
})
export class CvBuilderComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  cvData = { title: '', skills: '', experience: '', education: '' };
  candidateName: string = '';
  successMessage: string = '';
  isSaving: boolean = false;

  ngOnInit() {
    this.candidateName = localStorage.getItem('name') || 'Mon Profil';
    this.fetchCurrentCV();
  }

  // 📥 CHARGEMENT AUTOMATIQUE DU CV EXISTANT EN BD
  fetchCurrentCV() {
    const targetUrl = 'http://localhost:3000/api/candidate/cv/details'; // On créera cette route de lecture juste après
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => res.ok ? res.json() : null)
    .then(data => {
      if (data) {
        this.cvData.title = data.title || '';
        this.cvData.skills = data.skills || '';
        this.cvData.experience = data.experience || '';
        this.cvData.education = data.education || '';
        this.cdr.detectChanges();
      }
    })
    .catch(err => console.warn("Aucun CV existant trouvé, mode création actif."));
  }

  // Découpe la chaîne de caractères par les virgules pour faire les badges à droite
  getSkillsArray(): string[] {
    if (!this.cvData.skills) return [];
    return this.cvData.skills.split(',').filter(s => s.trim() !== '');
  }

  // 📤 ENREGISTREMENT OU MISE À JOUR DANS MYSQL
  onSaveCV(event: Event) {
    event.preventDefault();
    this.isSaving = true;

    const targetUrl = 'http://localhost:3000/api/candidate/cv/save'; // Route fournie dans votre candidate.routes.js
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : ''
      },
      body: JSON.stringify(this.cvData)
    })
    .then(async res => {
      if (!res.ok) throw new Error("Erreur de sauvegarde.");
      return res.json();
    })
    .then(() => {
      this.successMessage = "Votre CV en ligne a été enregistré et synchronisé avec succès !";
      this.isSaving = false;
      this.cdr.detectChanges();
      setTimeout(() => { this.successMessage = ''; this.cdr.detectChanges(); }, 3500);
    })
    .catch(err => {
      alert("Impossible de sauvegarder votre CV pour le moment.");
      this.isSaving = false;
      this.cdr.detectChanges();
    });
  }
}
<div class="cv-container-compact">
  
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-person-fill" style="color: #0ea5e9;"></i> Concepteur de CV Intelligent</h3>
      <p style="margin: 2px 0 0 0; color: #64748b; font-size: 13px;">Générez et synchronisez votre profil avec les recruteurs sur TunJob.</p>
    </div>
  </div>

  @if (successMessage) {
    <div class="alert-box-compact alert-success">{{ successMessage }}</div>
  }

  <!-- 📊 ARCHITECTURE DOUBLE PANNEAU ÉLARGIE -->
  <div class="cv-split-layout">
    
    <!-- ================= PANNEAU GAUCHE : SAISIE DES DONNÉES ================= -->
    <div class="cv-panel-card scrollable-form-panel">
      <form (ngSubmit)="onSaveCV($event)" class="compact-form-grid-vertical">
        
        <!-- 1. Informations de base & Titre -->
        <div class="form-section-title-inline"><i class="bi bi-person-badge"></i> Métier & Résumé</div>
        <div class="form-group-compact">
          <label>Titre de votre profil pro *</label>
          <input type="text" name="cv_title" [(ngModel)]="cvData.title" placeholder="Ex: Développeur Fullstack Angular / Node" required>
        </div>
        <div class="form-group-compact">
          <label>Accroche / Petit Résumé professionnel *</label>
          <textarea name="summary" [(ngModel)]="cvData.summary" rows="2" placeholder="Ex: Passionné par le web, spécialisé dans les architectures SPA..." required></textarea>
        </div>

        <!-- 2. Compétences en Tags -->
        <div class="form-section-title-inline" style="margin-top: 15px;"><i class="bi bi-tags"></i> Compétences</div>
        <div class="form-group-compact">
          <label>Compétences clés (Séparées par des virgules) *</label>
          <input type="text" name="skills" [(ngModel)]="cvData.skills" placeholder="Ex: Angular, TypeScript, SQL, Docker" required>
        </div>

        <!-- 3. Gestion Dynamique des Expériences -->
        <div class="form-section-title-inline-flex" style="margin-top: 15px;">
          <span><i class="bi bi-briefcase"></i> Expériences Professionnelles</span>
          <button type="button" class="btn-add-dynamic" (click)="addExperience()"><i class="bi bi-plus-circle-fill"></i> Ajouter</button>
        </div>
        
        @for (exp of cvData.experiences; track $index) {
          <div class="dynamic-entry-card">
            <div class="dynamic-entry-header">
              <span>Expérience #{{ $index + 1 }}</span>
              <button type="button" class="btn-remove-dynamic" (click)="removeExperience($index)"><i class="bi bi-trash3-fill"></i></button>
            </div>
            <div class="dynamic-fields-grid">
              <input type="text" name="exp_title_{{$index}}" [(ngModel)]="exp.job_title" placeholder="Poste (ex: Développeur Angular)" required>
              <input type="text" name="exp_comp_{{$index}}" [(ngModel)]="exp.company" placeholder="Entreprise (ex: TechTunisia)" required>
              <input type="text" name="exp_date_{{$index}}" [(ngModel)]="exp.duration" placeholder="Durée (ex: 2024 - Présent)" required>
              <textarea name="exp_desc_{{$index}}" [(ngModel)]="exp.description" rows="2" class="span-all-field" placeholder="Missions principales accomplies..." required></textarea>
            </div>
          </div>
        }

        <!-- 4. Gestion Dynamique des Formations -->
        <div class="form-section-title-inline-flex" style="margin-top: 15px;">
          <span><i class="bi bi-mortarboard"></i> Formations & Études</span>
          <button type="button" class="btn-add-dynamic" (click)="addEducation()"><i class="bi bi-plus-circle-fill"></i> Ajouter</button>
        </div>

        @for (edu of cvData.educations; track $index) {
          <div class="dynamic-entry-card">
            <div class="dynamic-entry-header">
              <span>Formation #{{ $index + 1 }}</span>
              <button type="button" class="btn-remove-dynamic" (click)="removeEducation($index)"><i class="bi bi-trash3-fill"></i></button>
            </div>
            <div class="dynamic-fields-grid">
              <input type="text" name="edu_deg_{{$index}}" [(ngModel)]="edu.degree" placeholder="Diplôme (ex: Licence Informatique)" required>
              <input type="text" name="edu_sch_{{$index}}" [(ngModel)]="edu.school" placeholder="École/Université (ex: ISG Tunis)" required>
              <input type="text" name="edu_year_{{$index}}" [(ngModel)]="edu.year" placeholder="Année (ex: 2024)" required>
            </div>
          </div>
        }

        <div class="form-actions-compact">
          <button type="submit" class="btn-save-cv-compact" [disabled]="isSaving">
            <i class="bi bi-cloud-arrow-up-fill"></i> Enregistrer et Publier mon CV
          </button>
        </div>
      </form>
    </div>

    <!-- ================= PANNEAU DROIT : RENDU LIVE PREVIEW A4 ================= -->
    <div class="cv-panel-card preview-bg">
      <div class="panel-inner-title"><i class="bi bi-eye-fill"></i> Maquette de rendu en temps réel</div>
      
      <div class="cv-paper-preview-pro">
        
        <!-- En-tête Pro avec Photo -->
        <div class="cv-header-preview-pro">
          <div class="cv-header-left-pro">
            <h4>{{ candidateName || 'Votre Nom & Prénom' }}</h4>
            <span class="cv-preview-subtitle-pro">{{ cvData.title || 'Intitulé de votre métier recherché' }}</span>
            @if (cvData.summary) {
              <p class="cv-summary-preview">{{ cvData.summary }}</p>
            }
          </div>
          <div class="cv-photo-preview-container">
            @if (avatarUrl) {
              <img [src]="avatarUrl" alt="Avatar">
            } @else {
              <i class="bi bi-person-fill" style="font-size: 36px; color: #cbd5e1;"></i>
            }
          </div>
        </div>

        <div class="cv-body-preview">
          <!-- Compétences -->
          <div class="cv-section-preview">
            <h5>Compétences</h5>
            <div class="cv-tags-container">
              @if (cvData.skills) {
                @for (skill of getSkillsArray(); track skill) {
                  <span class="skill-tag-preview">{{ skill.trim() }}</span>
                }
              } @else {
                <span class="empty-preview-text">Aucune compétence saisie.</span>
              }
            </div>
          </div>

          <!-- Expériences professionnelles -->
          <div class="cv-section-preview">
            <h5>Expériences Professionnelles</h5>
            @if (cvData.experiences.length > 0) {
              @for (exp of cvData.experiences; track exp) {
                <div class="preview-item-block">
                  <div class="preview-item-row">
                    <strong>{{ exp.job_title || 'Poste non spécifié' }}</strong>
                    <span class="preview-item-date">{{ exp.duration }}</span>
                  </div>
                  <span class="preview-item-sub">{{ exp.company }}</span>
                  <p class="preview-item-desc">{{ exp.description }}</p>
                </div>
              }
            } @else {
              <span class="empty-preview-text">Aucune expérience ajoutée pour le moment.</span>
            }
          </div>

          <!-- Formations -->
          <div class="cv-section-preview">
            <h5>Éducation & Formations</h5>
            @if (cvData.educations.length > 0) {
              @for (edu of cvData.educations; track edu) {
                <div class="preview-item-block">
                  <div class="preview-item-row">
                    <strong>{{ edu.degree || 'Diplôme non spécifié' }}</strong>
                    <span class="preview-item-date">{{ edu.year }}</span>
                  </div>
                  <span class="preview-item-sub">{{ edu.school }}</span>
                </div>
              }
            } @else {
              <span class="empty-preview-text">Aucune formation ajoutée pour le moment.</span>
            }
          </div>
        </div>

      </div>
    </div>

  </div>
</div>
